export type Cell = [number, number];

const isNeighbor = (cell: Cell, other: Cell): boolean => {
  const [x, y] = cell;
  const [ox, oy] = other;
  if (x === ox && y === oy) return false;
  return Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1;
};

const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number =>
  livingCells.filter((other) => isNeighbor(cell, other)).length;

const survivesNextGeneration = (cell: Cell, livingCells: Cell[]): boolean => {
  const neighbors = countLivingNeighbors(cell, livingCells);
  return neighbors === 2 || neighbors === 3;
};

export const nextGeneration = (livingCells: Cell[]): Cell[] =>
  livingCells.filter((cell) => survivesNextGeneration(cell, livingCells));
